//E. Negatives and Positives #include<bits/stdc++.h>using namespace std;#define int long long intsigned main(){    int t;    cin>>t;    while(t--){        int n;        cin>>n;        vector<int>arr(n);        int a=0,b=0;        for(int i=0;i<n;i++){            cin>>arr[i];            if(arr[i]<0){                a++;            }            arr[i]=abs(arr[i]);            b=b+arr[i];        }        sort(arr.begin(),arr.end());        if(a%2==0){            cout<<b<<endl;        }        else{            cout<<b-(2*arr[0])<<endl;        }    }}